arguments.new_str:
using System.IO.Compression;
using System.Text;

class ZipCreator
{
    void CreateArchive()
    {
        // .NET 9 breaking change: ZipArchive now defaults to UTF-8 and always
        // sets the EFS bit. The legacy Java consumer expects Shift-JIS, so we
        // must pass the encoding explicitly.
        Encoding.RegisterProvider(CodePagesEncodingProvider.Instance);
        Encoding shiftJis = Encoding.GetEncoding("shift_jis");
        using var archive = ZipFile.Open("data.zip", ZipArchiveMode.Create, shiftJis);
        archive.CreateEntry("レポート/月次.csv");  // Japanese path
        archive.CreateEntry("données/résumé.txt"); // French accented
    }
}

